from dataclasses import dataclass, field
from typing import Optional
from enum import Enum

class Direction(str, Enum):
    LOWER = "lower_better"
    HIGHER = "higher_better"

@dataclass
class KPI:
    name: str
    description: str
    formula: str
    unit: str
    direction: Direction
    baseline: float
    target: float
    target_horizon: str       # e.g. "12 months"
    measurement_source: str
    cadence: str
    owner: str
    parent_kpi: Optional[str] = None   # north-star name if this is a driver

    def improvement_required(self) -> float:
        """Absolute change needed from baseline to target."""
        return self.target - self.baseline

    def pct_improvement(self) -> float:
        """Percentage improvement from baseline."""
        if self.baseline == 0:
            return float("inf")
        return (self.target - self.baseline) / self.baseline * 100

@dataclass
class NorthStarFramework:
    feature_name: str
    north_star: KPI
    drivers: list[KPI] = field(default_factory=list)
    output_metrics: list[KPI] = field(default_factory=list)

    def validate(self) -> list[str]:
        errors = []
        if self.north_star.parent_kpi is not None:
            errors.append("North-star KPI should have no parent_kpi")
        for d in self.drivers:
            if d.parent_kpi != self.north_star.name:
                errors.append(f"Driver '{d.name}' should point to north star")
        for o in self.output_metrics:
            driver_names = {d.name for d in self.drivers}
            if o.parent_kpi not in driver_names:
                errors.append(f"Output metric '{o.name}' must link to a driver")
        return errors

    def summary(self) -> str:
        return (
            f"{self.feature_name}: NS={self.north_star.name} "
            f"({len(self.drivers)} drivers, {len(self.output_metrics)} output metrics)"
        )

